@overload
def exif_transpose(
    image: Image.Image, *, in_place: Literal[False] = False
) -> Image.Image: ...


def exif_transpose(image: Image.Image, *, in_place: bool = False) -> Image.Image | None:
    """
    If an image has an EXIF Orientation tag, other than 1, transpose the image
    accordingly, and remove the orientation data.

    :param image: The image to transpose.
    :param in_place: Boolean. Keyword-only argument.
        If ``True``, the original image is modified in-place, and ``None`` is returned.
        If ``False`` (default), a new :py:class:`~PIL.Image.Image` object is returned
        with the transposition applied. If there is no transposition, a copy of the
        image will be returned.
    """
    image.load()
    image_exif = image.getexif()
    orientation = image_exif.get(ExifTags.Base.Orientation, 1)
    method = {
        2: Image.Transpose.FLIP_LEFT_RIGHT,
        3: Image.Transpose.ROTATE_180,
        4: Image.Transpose.FLIP_TOP_BOTTOM,
        5: Image.Transpose.TRANSPOSE,
        6: Image.Transpose.ROTATE_270,
        7: Image.Transpose.TRANSVERSE,
        8: Image.Transpose.ROTATE_90,
    }.get(orientation)
    if method is not None:
        if in_place:
            image.im = image.im.transpose(method)
            image._size = image.im.size
        else:
            transposed_image = image.transpose(method)
        exif_image = image if in_place else transposed_image

        exif = exif_image.getexif()
        if ExifTags.Base.Orientation in exif:
            del exif[ExifTags.Base.Orientation]
            if "exif" in exif_image.info:
                exif_image.info["exif"] = exif.tobytes()
            elif "Raw profile type exif" in exif_image.info:
                exif_image.info["Raw profile type exif"] = exif.tobytes().hex()
            for key in ("XML:com.adobe.xmp", "xmp"):
                if key in exif_image.info:
                    for pattern in (
                        r'tiff:Orientation="([0-9])"',
                        r"<tiff:Orientation>([0-9])</tiff:Orientation>",
                    ):
                        value = exif_image.info[key]
                        exif_image.info[key] = (
                            re.sub(pattern, "", value)
                            if isinstance(value, str)
                            else re.sub(pattern.encode(), b"", value)
                        )
        if not in_place:
            return transposed_image
    elif not in_place:
        return image.copy()
    return None

def __getitem__(self, tag: int) -> Any:
    if tag not in self._tags_v2:  # unpack on the fly
        data = self._tagdata[tag]
        typ = self.tagtype[tag]
        size, handler = self._load_dispatch[typ]
        self[tag] = handler(self, data, self.legacy_api)  # check type
    val = self._tags_v2[tag]
    if self.legacy_api and not isinstance(val, (tuple, bytes)):
        val = (val,)
    return val

def __contains__(self, tag: object) -> bool:
    return tag in self._tags_v2 or tag in self._tagdata

def __setitem__(self, tag: int, value: Any) -> None:
    self._setitem(tag, value, self.legacy_api)

def _setitem(self, tag: int, value: Any, legacy_api: bool) -> None:
    basetypes = (Number, bytes, str)

    info = TiffTags.lookup(tag, self.group)
    values = [value] if isinstance(value, basetypes) else value

    if tag not in self.tagtype:
        if info.type:
            self.tagtype[tag] = info.type
        else:
            self.tagtype[tag] = TiffTags.UNDEFINED
            if all(isinstance(v, IFDRational) for v in values):
                for v in values:
                    assert isinstance(v, IFDRational)
                    if v < 0:
                        self.tagtype[tag] = TiffTags.SIGNED_RATIONAL
                        break
                else:
                    self.tagtype[tag] = TiffTags.RATIONAL
            elif all(isinstance(v, int) for v in values):
                short = True
                signed_short = True
                long = True
                for v in values:
                    assert isinstance(v, int)
                    if short and not (0 <= v < 2**16):
                        short = False
                    if signed_short and not (-(2**15) < v < 2**15):
                        signed_short = False
                    if long and v < 0:
                        long = False
                if short:
                    self.tagtype[tag] = TiffTags.SHORT
                elif signed_short:
                    self.tagtype[tag] = TiffTags.SIGNED_SHORT
                elif long:
                    self.tagtype[tag] = TiffTags.LONG
                else:
                    self.tagtype[tag] = TiffTags.SIGNED_LONG
            elif all(isinstance(v, float) for v in values):
                self.tagtype[tag] = TiffTags.DOUBLE
            elif all(isinstance(v, str) for v in values):
                self.tagtype[tag] = TiffTags.ASCII

